+                    if let Some(v) = child2.get(i) {
+                        prop_assert!(
+                            value_matches_type(v, &param.typ),
+                            "child2[{i}] = {v:?} doesn't match {:?}", param.typ
+                        );
+                    }
+                }
+            }
